/**
 * Return the argument unchanged.
 * @param {unknown} value
 * @returns {unknown}
 */
export function identity(value) {
  return value;
}

/**
 * Return a function that always yields the same value.
 * @param {unknown} value
 * @returns {() => unknown}
 */
export function constant(value) {
  return () => value;
}
